// Unit test for computeLegWarnings — exercises each risk flag in isolation,
// a clear case, and the riskLevel tiers (ok/caution/warning).
async function testComputeLegWarnings() {
  // Explicit thresholds so the test is independent of config values
  const t = {
    headwindAngleDeg: 60, headwindMinKnots: 10,
    lowVisPrecipMm: 2, lowVisCloudPct: 95,
    pressureLowHpa: 1005, pressureDropHpa: 3
  };

  const codesOf = (r) => r.warnings.map((w) => w.code);

  // --- Headwind: wind FROM the heading direction, strong enough ---
  const headwind = functions.call('computeLegWarnings', 90,
    { windDirection: 90, windSpeed: 15, precipitation: 0, cloudCover: 10, pressure: 1015 },
    null, 1000, 5000, 100, t);
  assert(codesOf(headwind).indexOf('headwind') >= 0, 'Head-on strong wind flags headwind');
  assertEquals(headwind.riskLevel, 'caution', 'Single warning is caution');

  // Wind from astern is NOT a headwind
  const tailwind = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 15, precipitation: 0, cloudCover: 10, pressure: 1015 },
    null, 1000, 5000, 100, t);
  assert(codesOf(tailwind).indexOf('headwind') < 0, 'Tailwind should not flag headwind');

  // Light head-on wind (below min knots) is NOT a headwind
  const lightHead = functions.call('computeLegWarnings', 90,
    { windDirection: 90, windSpeed: 5, precipitation: 0, cloudCover: 10, pressure: 1015 },
    null, 1000, 5000, 100, t);
  assert(codesOf(lightHead).indexOf('headwind') < 0, 'Light head-on wind should not flag headwind');

  // --- Low visibility via heavy precipitation ---
  const rain = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 5, precipitation: 4, cloudCover: 10, pressure: 1015 },
    null, 1000, 5000, 100, t);
  assert(codesOf(rain).indexOf('low_visibility') >= 0, 'Heavy precip flags low visibility');

  // --- Low visibility via near-total overcast ---
  const overcast = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 5, precipitation: 0, cloudCover: 97, pressure: 1015 },
    null, 1000, 5000, 100, t);
  assert(codesOf(overcast).indexOf('low_visibility') >= 0, 'Near-total overcast flags low visibility');

  // --- Pressure drop via low absolute pressure ---
  const lowP = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 5, precipitation: 0, cloudCover: 10, pressure: 1000 },
    null, 1000, 5000, 100, t);
  assert(codesOf(lowP).indexOf('pressure_drop') >= 0, 'Low absolute pressure flags pressure drop');

  // --- Pressure drop via a sharp hour-over-hour fall ---
  const fallP = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 5, precipitation: 0, cloudCover: 10, pressure: 1009 },
    { pressure: 1014 }, 1000, 5000, 100, t);
  assert(codesOf(fallP).indexOf('pressure_drop') >= 0, 'Sharp pressure fall flags pressure drop');

  // --- Arrival after sunset ---
  const night = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 5, precipitation: 0, cloudCover: 10, pressure: 1015 },
    null, 6000, 5000, 100, t);
  assert(codesOf(night).indexOf('after_sunset') >= 0, 'Arrival past sunset flags after_sunset');

  // --- Clear case: no warnings, riskLevel ok ---
  const clear = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 5, precipitation: 0, cloudCover: 10, pressure: 1015 },
    null, 1000, 5000, 100, t);
  assertEquals(clear.warnings.length, 0, 'Benign conditions produce no warnings');
  assertEquals(clear.riskLevel, 'ok', 'No warnings is ok');

  // --- Two concurrent warnings → riskLevel warning ---
  const twoRisks = functions.call('computeLegWarnings', 90,
    { windDirection: 270, windSpeed: 5, precipitation: 4, cloudCover: 10, pressure: 1015 },
    null, 6000, 5000, 100, t);
  assert(twoRisks.warnings.length >= 2, 'Should have low-vis + after-sunset');
  assertEquals(twoRisks.riskLevel, 'warning', 'Two or more warnings is warning');
}
